import{c as e,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Making Playgrounds using Claude Code — @trq212","description":"","frontmatter":{"title":"Making Playgrounds using Claude Code — @trq212","author":"Thariq（@trq212）","date":"2026-01-29T00:00:00.000Z","source":"https://x.com/trq212/status/2017024445244924382","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-01-29-@trq212-924382.md","filePath":"research/tweets/2026-01-29-@trq212-924382.md","lastUpdated":1779894392000}'),l={name:"research/tweets/2026-01-29-@trq212-924382.md"};function n(i,t,d,s,u,p){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="making-playgrounds-using-claude-code-—-trq212" tabindex="-1">Making Playgrounds using Claude Code — @trq212 <a class="header-anchor" href="#making-playgrounds-using-claude-code-—-trq212" aria-label="Permalink to &quot;Making Playgrounds using Claude Code — @trq212&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/trq212/status/2017024445244924382" target="_blank" rel="noreferrer">https://x.com/trq212/status/2017024445244924382</a><strong>作者</strong>：Thariq（@trq212） <strong>發布日期</strong>：2026-01-29 <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：Twitter Article <strong>統計</strong>：2825 likes · 273 retweets · 5159 bookmarks · 847655 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>We&#39;ve published a new Claude Code plugin called playground that helps Claude generate HTML playgrounds. These are standalone HTML files that let you visualize a problem with Claude, interact with it and give you an output prompt to paste back into Claude Code.</p><p>I&#39;ve found this can be really good interacting with the model in ways that are not well suited for text, for example to:</p><ul><li>Visualize the architecture of the codebase</li><li>Adjust the design of a component</li><li>Brainstorm layouting and design</li><li>Tweak the balance of a game</li></ul><p>To get started, install the plugin in Claude code by running the following commands: /plugin marketplace update claude-plugins-official /plugin install playground@claude-plugins-official</p><p>Here are some of my favorite playgrounds I&#39;ve made:</p><p><strong>Changing the design of the AskUserQuestion Tool in Claude Code</strong> prompt: &quot;Use the playground skill to create an playground that helps me explore new layout changes to the AskUserQuestion Tool&quot;</p><p><strong>Critiquing your writing and getting a response</strong> prompt: &quot;Use the playground skill to review my SKILL.MD and give me inline suggestions I can approve, reject or comment&quot;</p><p><strong>Tweaking a Remotion Video Intro</strong> prompt: &quot;Use the playground skill to tweak my intro screen to be more interesting and delightful&quot;</p><p><strong>Viewing an Architecture Diagram and letting the user comment</strong> prompt: &quot;Use the playground skill to show how this email agent codebase works and let me comment on particular nodes in the architecture to ask questions, make edits, etc&quot;</p><p><strong>Balancing the Superhero Rogue-like game I&#39;m making</strong> prompt: &quot;Use the playground skill to help me balance the &#39;Inferno&#39; hero&#39;s deck&quot;</p><p>Excited to see how you all explore this!</p><p>My tip for creating an interesting playground- think of a unique way of interacting with the model and then ask it to express that. I think you might find it surprising.</p><p>If you make something cool, please share it!</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Code 官方 playground plugin 讓 Claude 生成互動式 HTML 介面，補足純文字互動的視覺化缺口。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><code>playground</code> plugin 讓 Claude 輸出獨立 HTML 檔案，可在瀏覽器互動後將結果 prompt 貼回 Claude Code，形成 human-in-the-loop 視覺化迴圈</li><li>最適用場景：架構圖視覺化、UI 設計調整、遊戲平衡調整等「文字不適合表達」的任務</li><li>安裝方式明確：兩行 <code>/plugin</code> 指令即可啟用（<code>claude-plugins-official</code> marketplace）</li><li>5 個具體 prompt 範例涵蓋不同使用情境（設計、寫作審查、影片 intro、架構圖、遊戲平衡）</li><li>作者建議：先想「這個問題適合什麼互動方式」，再讓模型表達——而非直接要求輸出</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>Plugin 名稱：<code>playground@claude-plugins-official</code></li><li>安裝指令：<code>/plugin marketplace update claude-plugins-official</code> + <code>/plugin install playground@claude-plugins-official</code></li><li>輸出格式：standalone HTML 檔案</li><li>互動流程：Claude 生成 HTML → 瀏覽器互動 → 輸出 prompt → 貼回 Claude Code</li><li>作者：Thariq，Claude Code team @Anthropic</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>文章為公告性質，非教學深度</strong>：缺乏 plugin 內部運作機制說明（Claude 如何生成 HTML、是否有 template）；5 個範例全是 prompt，沒有實際截圖或輸出結果（影片素材在原推文但無法透過 API 取得）</li><li><strong>互動迴圈價值高，但門檻不明</strong>：HTML playground 的「輸出 prompt 貼回 Claude Code」流程依賴用戶手動複製貼上，是否有 CLI 直接整合仍不清楚；cc-workspace 若要採用需先確認 plugin 系統相容性</li><li><strong>泛化性強但高度依賴 Claude Code plugin 生態</strong>：不適用於非 Claude Code 環境；且 <code>claude-plugins-official</code> marketplace 目前不在 cc-workspace 的常用工具集內</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>安裝指令明確，兩行即可試用；但需確認 cc-workspace 的 plugin 系統是否已啟用，且範例 prompt 可直接複用</td></tr><tr><td>B. 創新性 (20%)</td><td>8/10</td><td>HTML playground 作為視覺化互動層是新概念，補足 Claude Code 純文字互動缺口；與現有 skills 無重疊</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>5 個範例均為作者自述，無量化數據、無外部驗證；影片示範無法透過 API 取得</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>只有 prompt 範例，無 plugin 實作原理、HTML 生成機制、或參數說明</td></tr><tr><td>E. 泛化性 (15%)</td><td>6/10</td><td>概念跨領域（設計/遊戲/架構），但強依賴 Claude Code plugin 生態，非 Claude Code 環境無法複用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.5/10</strong></td><td>7×0.3+8×0.2+5×0.2+5×0.15+6×0.15 = 2.1+1.6+1.0+0.75+0.90 = <strong>6.35 ≈ 6.5</strong></td></tr></tbody></table><p><strong>整合決策</strong>：Skip（僅歸檔） <strong>理由</strong>：總分 6.5，未達 &gt; 6 整合門檻（恰達邊緣）；plugin 概念值得觀察，但缺乏技術深度與可驗證證據，建議先試用 playground plugin 後再評估是否整合為 SKILL</p>',30)])])}const h=e(l,[["render",n]]);export{c as __pageData,h as default};
